DROP TABLE IF EXISTS `processo_enviado`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `processo_enviado` (
  `processo_formatado` varchar(255) NOT NULL,
  `link_acesso` varchar(255) DEFAULT NULL,
  `especificacao` varchar(255) DEFAULT NULL,
  `id_unidade_geradora` varchar(255) DEFAULT NULL,
  `geracao_sigla` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `geracao_data` datetime DEFAULT NULL,
  `geracao_descricao` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci,
  `usuario_gerador` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `ultimo_andamento_sigla` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `ultimo_andamento_descricao` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci,
  `ultimo_andamento_data` datetime DEFAULT NULL,
  `ultimo_andamento_usuario` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `natureza_despesa` int DEFAULT NULL,
  `fonte` int DEFAULT NULL,
  `acao` int DEFAULT NULL,
  `objeto_do_pedido` text,
  `necessidade` text,
  `deliberacao` text,
  `tipo_despesa` varchar(50) DEFAULT NULL,
  `data_da_reuniao` date DEFAULT NULL,
  `valor_solicitado` decimal(12,2) DEFAULT NULL,
  `valor_aprovado` decimal(12,2) DEFAULT NULL,
  `tramitado_sead_cgfr` varchar(50) DEFAULT NULL,
