  `data_devolvido_cgfr_sead` varchar(50) DEFAULT NULL,
  `tipo_processo` varchar(100) DEFAULT NULL,
  `fornecedor` varchar(255) DEFAULT NULL,
  `observacao` text,
  `possui_reserva` int DEFAULT '0',
  `valor_reserva` decimal(12,2) DEFAULT NULL,
  PRIMARY KEY (`processo_formatado`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
